(function(){"use strict";document.addEventListener("DOMContentLoaded",function(){var t=document.querySelector(".nav-toggle"),n=document.querySelector(".nav-links");if(!(!t||!n)){t.addEventListener("click",function(){t.classList.toggle("active"),n.classList.toggle("open")}),n.querySelectorAll("a").forEach(function(e){e.addEventListener("click",function(){t.classList.remove("active"),n.classList.remove("open")})}),document.addEventListener("click",function(e){!t.contains(e.target)&&!n.contains(e.target)&&(t.classList.remove("active"),n.classList.remove("open"))});var o=document.querySelectorAll(".nav-dropdown-toggle");o.forEach(function(e){e.addEventListener("click",function(i){i.preventDefault();var a=e.getAttribute("aria-expanded")==="true";e.setAttribute("aria-expanded",String(!a));var c=e.nextElementSibling;c&&c.classList.toggle("open")})}),document.addEventListener("keydown",function(e){e.key==="Escape"&&o.forEach(function(i){i.setAttribute("aria-expanded","false");var a=i.nextElementSibling;a&&a.classList.remove("open")})})}})})();
